defmodule MyAppWeb.PostView do
  use MyAppWeb, :view

  defp allowed_tags(html) when is_binary(html), do: html |> Phoenix.HtmlSanitizer.sanitize()

  defp render_tags(content) do
    content
    |> replace(~r/<\s*[^>]*>/, &allowed_tags/2)
  end

  def render(assigns) do
    ~L"""
    <%= raw @post.content %>
    """
  end
end